SELECT AVG(km_travelled) AS average_distance
FROM transactions
WHERE city_id = (SELECT city_id FROM cities WHERE city_name = 'New York City');

SELECT average_distance, max_distance
FROM customer_statistics
WHERE customer_id = (SELECT customer_id FROM customers WHERE name = 'John Doe');

SELECT AVG(km_travelled) AS average_distance
FROM transactions
WHERE payment_mode = 'Cash' AND rating >= 4;

SELECT COUNT(*) AS total_trips
FROM transactions
WHERE city_id = 0 AND strftime('%Y', date_of_travel) = '2018';
